import{_ as n,c as i,o as a,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"DM-Pairing und Zugriffskontrolle: Schützen Sie Ihren AI-Assistenten | Clawdbot-Tutorial","description":"Erfahren Sie mehr über den DM-Pairing-Schutzmechanismus von Clawdbot, lernen Sie, wie Sie Pairing-Anfragen von unbekannten Absendern über CLI genehmigen, ausstehende Anfragen auflisten und die Allowlist verwalten. Dieses Tutorial führt vollständig durch den Pairing-Prozess, CLI-Befehle, Zugriffspolicy-Konfiguration und Sicherheits-Praktiken, inklusive Troubleshooting und dem Doctor-Befehl.","frontmatter":{"title":"DM-Pairing und Zugriffskontrolle: Schützen Sie Ihren AI-Assistenten | Clawdbot-Tutorial","sidebarTitle":"Zugriff von Fremden verwalten","subtitle":"DM-Pairing und Zugriffskontrolle: Schützen Sie Ihren AI-Assistenten","description":"Erfahren Sie mehr über den DM-Pairing-Schutzmechanismus von Clawdbot, lernen Sie, wie Sie Pairing-Anfragen von unbekannten Absendern über CLI genehmigen, ausstehende Anfragen auflisten und die Allowlist verwalten. Dieses Tutorial führt vollständig durch den Pairing-Prozess, CLI-Befehle, Zugriffspolicy-Konfiguration und Sicherheits-Praktiken, inklusive Troubleshooting und dem Doctor-Befehl.","tags":["Einsteiger","Sicherheit","Pairing","Zugriffskontrolle"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"de/moltbot/moltbot/start/pairing-approval/index.md","filePath":"de/moltbot/moltbot/start/pairing-approval/index.md"}'),s={name:"de/moltbot/moltbot/start/pairing-approval/index.md"};function r(l,e,d,o,h,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="dm-pairing-und-zugriffskontrolle-schutzen-sie-ihren-ai-assistenten" tabindex="-1">DM-Pairing und Zugriffskontrolle: Schützen Sie Ihren AI-Assistenten <a class="header-anchor" href="#dm-pairing-und-zugriffskontrolle-schutzen-sie-ihren-ai-assistenten" aria-label="Permalink to &quot;DM-Pairing und Zugriffskontrolle: Schützen Sie Ihren AI-Assistenten&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><p>Nach Abschluss dieses Tutorials können Sie:</p><ul><li>✅ Den standardmäßigen DM-Pairing-Schutzmechanismus verstehen</li><li>✅ Pairing-Anfragen von unbekannten Absendern genehmigen</li><li>✅ Ausstehende Pairing-Anfragen auflisten und verwalten</li><li>✅ Verschiedene DM-Zugriffspolicies konfigurieren (pairing/allowlist/open)</li><li>✅ Doctor-Prüfungen für Sicherheitskonfigurationen ausführen</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Vielleicht haben Sie gerade einen WhatsApp- oder Telegram-Kanal konfiguriert und möchten mit Ihrem AI-Assistenten chatten, stoßen aber auf folgende Probleme:</p><ul><li>&quot;Warum antwortet Clawdbot nicht, wenn Fremde mir Nachrichten schicken?&quot;</li><li>&quot;Ich habe einen Pairing-Code erhalten, weiß aber nicht, was das bedeutet&quot;</li><li>&quot;Ich möchte jemanden genehmigen, weiß aber nicht, welchen Befehl ich verwenden soll&quot;</li><li>&quot;Wie kann ich prüfen, wer auf Genehmigung wartet?&quot;</li></ul><p>Die gute Nachricht: <strong>Clawdbot aktiviert standardmäßig den DM-Pairing-Schutz</strong>, um sicherzustellen, dass nur von Ihnen autorisierte Absender mit Ihrem AI-Assistenten kommunizieren können.</p><h2 id="wann-sie-diese-methode-verwenden" tabindex="-1">Wann Sie diese Methode verwenden <a class="header-anchor" href="#wann-sie-diese-methode-verwenden" aria-label="Permalink to &quot;Wann Sie diese Methode verwenden&quot;">​</a></h2><p>Verwenden Sie diese Methode, wenn Sie:</p><ul><li>🛡 <strong>Datenschutz schützen</strong> müssen: Sicherstellen, dass nur vertrauenswürdige Personen mit Ihrem AI-Assistenten chatten können</li><li>✅ <strong>Fremde genehmigen</strong> müssen: Neuen Absendern den Zugriff auf Ihren AI-Assistenten ermöglichen</li><li>🔒 <strong>Strikte Zugriffskontrolle</strong> benötigen: Zugriffsrechte für bestimmte Benutzer einschränken</li><li>📋 <strong>Massenverwaltung</strong> durchführen müssen: Alle ausstehenden Pairing-Anfragen anzeigen und verwalten</li></ul><hr><h2 id="kerngedanke" tabindex="-1">Kerngedanke <a class="header-anchor" href="#kerngedanke" aria-label="Permalink to &quot;Kerngedanke&quot;">​</a></h2><h3 id="was-ist-dm-pairing" tabindex="-1">Was ist DM-Pairing? <a class="header-anchor" href="#was-ist-dm-pairing" aria-label="Permalink to &quot;Was ist DM-Pairing?&quot;">​</a></h3><p>Clawdbot verbindet sich mit echten Messaging-Plattformen (WhatsApp, Telegram, Slack usw.), und <strong>Privatchats (DMs) werden auf diesen Plattformen standardmäßig als nicht vertrauenswürdige Eingaben betrachtet</strong>.</p><p>Um Ihren AI-Assistenten zu schützen, bietet Clawdbot einen <strong>Pairing-Mechanismus</strong>:</p><div class="info custom-block"><p class="custom-block-title">Pairing-Prozess</p><ol><li>Ein unbekannter Absender sendet Ihnen eine Nachricht</li><li>Clawdbot erkennt, dass der Absender nicht autorisiert ist</li><li>Clawdbot gibt einen <strong>Pairing-Code</strong> zurück (8 Zeichen)</li><li>Der Absender muss Ihnen den Pairing-Code mitteilen</li><li>Sie genehmigen den Code über die CLI</li><li>Die Absender-ID wird zur Allowlist hinzugefügt</li><li>Der Absender kann normal mit dem AI-Assistenten chatten</li></ol></div><h3 id="standard-dm-policy" tabindex="-1">Standard-DM-Policy <a class="header-anchor" href="#standard-dm-policy" aria-label="Permalink to &quot;Standard-DM-Policy&quot;">​</a></h3><p><strong>Alle Kanäle verwenden standardmäßig <code>dmPolicy=&quot;pairing&quot;</code></strong>, das bedeutet:</p><table tabindex="0"><thead><tr><th>Policy</th><th>Verhalten</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>Unbekannte Absender erhalten einen Pairing-Code, Nachricht wird nicht verarbeitet (Standard)</td></tr><tr><td><code>allowlist</code></td><td>Nur Absender aus der <code>allowFrom</code>-Liste sind zulässig</td></tr><tr><td><code>open</code></td><td>Alle Absender sind zulässig (erfordert explizite Konfiguration von <code>&quot;*&quot;</code>)</td></tr><tr><td><code>disabled</code></td><td>DM-Funktionalität vollständig deaktiviert</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Sicherheitshinweis</p><p>Der Standardmodus <code>pairing</code> ist die sicherste Wahl. Ändern Sie nicht in den Modus <code>open</code>, es sei denn, Sie haben spezielle Anforderungen.</p></div><hr><h2 id="🎒-vorbereitungen-vor-dem-start" tabindex="-1">🎒 Vorbereitungen vor dem Start <a class="header-anchor" href="#🎒-vorbereitungen-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitungen vor dem Start&quot;">​</a></h2><p>Stellen Sie sicher, dass Sie:</p><ul><li>[x] Das Tutorial <a href="./../getting-started/">Schnellstart</a> abgeschlossen haben</li><li>[x] Das Tutorial <a href="./../gateway-startup/">Gateway starten</a> abgeschlossen haben</li><li>[x] Mindestens einen Messaging-Kanal konfiguriert haben (WhatsApp, Telegram, Slack usw.)</li><li>[x] Der Gateway läuft</li></ul><hr><h2 id="fuhren-sie-dies-schritt-fur-schritt-aus" tabindex="-1">Führen Sie dies Schritt für Schritt aus <a class="header-anchor" href="#fuhren-sie-dies-schritt-fur-schritt-aus" aria-label="Permalink to &quot;Führen Sie dies Schritt für Schritt aus&quot;">​</a></h2><h3 id="schritt-1-verstehen-sie-woher-der-pairing-code-stammt" tabindex="-1">Schritt 1: Verstehen Sie, woher der Pairing-Code stammt <a class="header-anchor" href="#schritt-1-verstehen-sie-woher-der-pairing-code-stammt" aria-label="Permalink to &quot;Schritt 1: Verstehen Sie, woher der Pairing-Code stammt&quot;">​</a></h3><p>Wenn ein unbekannter Absender eine Nachricht an Ihren Clawdbot sendet, erhält er eine Antwort ähnlich wie diese:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>Wichtige Eigenschaften des Pairing-Codes</strong> (Quelle: <code>src/pairing/pairing-store.ts</code>):</p><ul><li><strong>8 Zeichen</strong>: Einfach einzugeben und zu merken</li><li><strong>Großbuchstaben und Ziffern</strong>: Vermeidet Verwirrung</li><li><strong>Vermeidung leicht zu verwechselnder Zeichen</strong>: Enthält keine 0, O, 1, I</li><li><strong>1 Stunde Gültigkeit</strong>: Läuft automatisch nach Ablauf der Zeit ab</li><li><strong>Maximal 3 ausstehende Genehmigungsanfragen</strong>: Älteste Anfragen werden automatisch gelöscht, wenn überschritten</li></ul><h3 id="schritt-2-auflisten-ausstehender-pairing-anfragen" tabindex="-1">Schritt 2: Auflisten ausstehender Pairing-Anfragen <a class="header-anchor" href="#schritt-2-auflisten-ausstehender-pairing-anfragen" aria-label="Permalink to &quot;Schritt 2: Auflisten ausstehender Pairing-Anfragen&quot;">​</a></h3><p>Führen Sie den folgenden Befehl im Terminal aus:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>Wenn keine ausstehenden Anfragen vorliegen, sehen Sie:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Unterstützte Kanäle</p><p>Die Pairing-Funktion unterstützt die folgenden Kanäle:</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="schritt-3-pairing-anfrage-genehmigen" tabindex="-1">Schritt 3: Pairing-Anfrage genehmigen <a class="header-anchor" href="#schritt-3-pairing-anfrage-genehmigen" aria-label="Permalink to &quot;Schritt 3: Pairing-Anfrage genehmigen&quot;">​</a></h3><p>Verwenden Sie den vom Absender bereitgestellten Pairing-Code, um den Zugriff zu genehmigen:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Wirkung nach Genehmigung</p><p>Nach der Genehmigung wird die Absender-ID (123456789) automatisch zur Allowlist dieses Kanals hinzugefügt und unter folgendem Pfad gespeichert: <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="schritt-4-absender-benachrichtigen-optional" tabindex="-1">Schritt 4: Absender benachrichtigen (optional) <a class="header-anchor" href="#schritt-4-absender-benachrichtigen-optional" aria-label="Permalink to &quot;Schritt 4: Absender benachrichtigen (optional)&quot;">​</a></h3><p>Wenn Sie den Absender automatisch benachrichtigen möchten, verwenden Sie das <code>--notify</code>-Flag:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>Der Absender erhält die folgende Nachricht (Quelle: <code>src/channels/plugins/pairing-message.ts</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>Hinweis</strong>: Das <code>--notify</code>-Flag erfordert, dass der Clawdbot-Gateway läuft und der Kanal aktiv ist.</p><h3 id="schritt-5-verifizieren-dass-der-absender-normal-chatten-kann" tabindex="-1">Schritt 5: Verifizieren, dass der Absender normal chatten kann <a class="header-anchor" href="#schritt-5-verifizieren-dass-der-absender-normal-chatten-kann" aria-label="Permalink to &quot;Schritt 5: Verifizieren, dass der Absender normal chatten kann&quot;">​</a></h3><p>Lassen Sie den Absender erneut eine Nachricht senden, der AI-Assistent sollte normal antworten.</p><hr><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Führen Sie die folgenden Überprüfungen durch, um sicherzustellen, dass die Konfiguration korrekt ist:</p><ul><li>[ ] Mit <code>clawdbot pairing list &lt;channel&gt;</code> können Sie ausstehende Anfragen anzeigen</li><li>[ ] Mit <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> können Sie Anfragen erfolgreich genehmigen</li><li>[ ] Der genehmigte Absender kann normal mit dem AI-Assistenten chatten</li><li>[ ] Pairing-Codes laufen nach 1 Stunde automatisch ab (kann durch erneutes Senden einer Nachricht verifiziert werden)</li></ul><hr><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="fehler-1-pairing-code-nicht-gefunden" tabindex="-1">Fehler 1: Pairing-Code nicht gefunden <a class="header-anchor" href="#fehler-1-pairing-code-nicht-gefunden" aria-label="Permalink to &quot;Fehler 1: Pairing-Code nicht gefunden&quot;">​</a></h3><p><strong>Fehlermeldung</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>Mögliche Ursachen</strong>:</p><ul><li>Der Pairing-Code ist abgelaufen (mehr als 1 Stunde)</li><li>Der Pairing-Code wurde falsch eingegeben (Groß-/Kleinschreibung prüfen)</li><li>Der Absender hat tatsächlich keine Nachricht gesendet (Pairing-Codes werden nur generiert, wenn eine Nachricht empfangen wurde)</li></ul><p><strong>Lösung</strong>:</p><ul><li>Lassen Sie den Absender erneut eine Nachricht senden, um einen neuen Pairing-Code zu generieren</li><li>Stellen Sie sicher, dass der Pairing-Code korrekt kopiert wurde (Groß-/Kleinschreibung beachten)</li></ul><h3 id="fehler-2-kanal-unterstutzt-kein-pairing" tabindex="-1">Fehler 2: Kanal unterstützt kein Pairing <a class="header-anchor" href="#fehler-2-kanal-unterstutzt-kein-pairing" aria-label="Permalink to &quot;Fehler 2: Kanal unterstützt kein Pairing&quot;">​</a></h3><p><strong>Fehlermeldung</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>Mögliche Ursachen</strong>:</p><ul><li>Der Kanalname wurde falsch geschrieben</li><li>Dieser Kanal unterstützt die Pairing-Funktion nicht</li></ul><p><strong>Lösung</strong>:</p><ul><li>Führen Sie <code>clawdbot pairing list</code> aus, um die Liste der unterstützten Kanäle anzuzeigen</li><li>Verwenden Sie den korrekten Kanalnamen</li></ul><h3 id="fehler-3-benachrichtigung-fehlgeschlagen" tabindex="-1">Fehler 3: Benachrichtigung fehlgeschlagen <a class="header-anchor" href="#fehler-3-benachrichtigung-fehlgeschlagen" aria-label="Permalink to &quot;Fehler 3: Benachrichtigung fehlgeschlagen&quot;">​</a></h3><p><strong>Fehlermeldung</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>Mögliche Ursachen</strong>:</p><ul><li>Der Gateway läuft nicht</li><li>Die Kanalverbindung ist unterbrochen</li><li>Netzwerkprobleme</li></ul><p><strong>Lösung</strong>:</p><ul><li>Stellen Sie sicher, dass der Gateway läuft</li><li>Prüfen Sie den Kanalstatus: <code>clawdbot channels status</code></li><li>Verwenden Sie nicht das <code>--notify</code>-Flag und benachrichtigen Sie den Absender manuell</li></ul><hr><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Dieses Tutorial hat den DM-Pairing-Schutzmechanismus von Clawdbot vorgestellt:</p><ul><li><strong>Standardsicherheit</strong>: Alle Kanäle verwenden standardmäßig den Modus <code>pairing</code>, um Ihren AI-Assistenten zu schützen</li><li><strong>Pairing-Prozess</strong>: Unbekannte Absender erhalten einen 8-stelligen Pairing-Code, den Sie über die CLI genehmigen müssen</li><li><strong>Verwaltungsbefehle</strong>: <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>: Auflisten ausstehender Anfragen</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>: Pairing genehmigen</li></ul></li><li><strong>Speicherort</strong>: Die Allowlist wird unter <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code> gespeichert</li><li><strong>Automatisches Ablaufen</strong>: Pairing-Anfragen laufen nach 1 Stunde automatisch ab</li></ul><p>Denken Sie daran: <strong>Der Pairing-Mechanismus ist das Sicherheitsfundament von Clawdbot</strong> und stellt sicher, dass nur von Ihnen autorisierte Personen mit Ihrem AI-Assistenten chatten können.</p><hr><h2 id="vorschau-auf-das-nachste-tutorial" tabindex="-1">Vorschau auf das nächste Tutorial <a class="header-anchor" href="#vorschau-auf-das-nachste-tutorial" aria-label="Permalink to &quot;Vorschau auf das nächste Tutorial&quot;">​</a></h2><blockquote><p>Im nächsten Tutorial lernen wir <strong><a href="./../../faq/troubleshooting/">Fehlerbehebung: Häufige Probleme lösen</a></strong>.</p><p>Sie lernen:</p><ul><li>Schnelle Diagnose und Systemstatus-Prüfung</li><li>Lösungen für Gateway-Start, Kanalverbindung, Authentifizierungsfehler und andere Probleme</li><li>Fehlerbehebung bei fehlgeschlagenen Tool-Aufrufen und Performance-Optimierung</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert am: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Standard-DM-Policy (pairing)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>: Länge des Pairing-Codes</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>: Zeichensatz für Pairing-Codes (ohne 0O1I)</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>: Gültigkeitsdauer für Pairing-Anfragen (1 Stunde)</li><li><code>PAIRING_PENDING_MAX = 3</code>: Maximale Anzahl ausstehender Genehmigungsanfragen</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>approveChannelPairingCode()</code>: Pairing-Code genehmigen und zur Allowlist hinzufügen</li><li><code>listChannelPairingRequests()</code>: Ausstehende Pairing-Anfragen auflisten</li><li><code>upsertChannelPairingRequest()</code>: Pairing-Anfrage erstellen oder aktualisieren</li><li><code>addChannelAllowFromStoreEntry()</code>: Absender zur Allowlist hinzufügen</li></ul></details>`,92)])])}const p=n(s,[["render",r]]);export{u as __pageData,p as default};
